// SweepBright retourne { data: [...contacts] }
const response = $input.first().json;
const contacts = response.data || response.contacts || response || [];

if (!Array.isArray(contacts) || contacts.length === 0) {
  return [];
}

return contacts.map(c => {
  // Adapter selon la structure réelle de l'API SweepBright
  const firstName = c.first_name || c.firstName || '';
  const lastName  = c.last_name  || c.lastName  || '';
  const email     = c.email || (c.emails && c.emails[0]?.address) || '';
  const phone     = c.phone || c.mobile || (c.phones && c.phones[0]?.number) || '';

  // Propriété d'intérêt (premier bien de la liste si plusieurs)
  const prop = (c.properties_of_interest && c.properties_of_interest[0]) || c.property || {};
  const bien = prop.type ? `${prop.type} ${prop.bedrooms ? prop.bedrooms + ' ch.' : ''}`.trim() : '';
  const ville = prop.city || prop.location || '';

  // Message / notes
  const message = c.notes || c.message || c.description || '';

  return {
    json: {
      id: 'sb_' + (c.id || c.uuid || String(Date.now())),
      prenom: firstName,
      nom: lastName,
      email,
      tel: phone,
      bien,
      ville,
      source: 'sweepbright',
      projet: c.project_type || c.interest_type || '',
      message
    }
  };
});
